import base64
from hashlib import sha256
from time import time
from secrets import token_hex
from pyotp import TOTP

class MFASystem:
    def __init__(self):
        self.totp = TOTP()
    
    def generate_secret(self):
        secret = token_hex(32)
        return secret
    
    def create_qr_code(self, secret):
        qr_code = b64encode(sha256(secret.encode('utf-8')).digest())
        return qr_code
    
    def validate_otp(self, otp, secret):
        expected_value = self.totp.get_totp(secret, time())
        if expected_value == otp:
            return True
        else:
            return False